CREATE TABLE Customers (
  Name VARCHAR(50),
  Email VARCHAR(50)  -- Not unique
);

-- Orders table with foreign key referencing Email
CREATE TABLE Orders (
  OrderID INT PRIMARY KEY,
  CustomerEmail VARCHAR(50),
  Amount DECIMAL(10, 2),
  FOREIGN KEY (CustomerEmail) REFERENCES Customers(Email)
);

